using namespace std;

class Solution {
public:
    int minStartingIndex(string s, string pattern) {
        int n = s.size();
        int m = pattern.size();
        for (int i = 0; i <= n - m; ++i) {
            int mismatches = 0;
            for (int j = 0; j < m; ++j) {
                if (s[i + j] != pattern[j]) {
                    ++mismatches;
                    if (mismatches > 1) {
                        break;
                    }
                }
            }
            if (mismatches <= 1) {
                return i;
            }
        }
        return -1;
    }
};

